script:
loading_sheets = json.loads(frappe.form_dict.loading_sheets)

doc = frappe.new_doc("Dispatch Sheet")

for sheet_name in loading_sheets:
    date = frappe.db.get_value("Loading Sheet", sheet_name, "date")
    doc.append("loading_sheets", {
        "loading_sheet": sheet_name,
        "date": date
    })

doc.insert()
frappe.response["message"] = doc.name

if doc.purpose != "Manufacture":
    frappe.log_error("QR Batch Logic Skipped", f"Stock Entry {doc.name} is not a Manufacturing entry.")
else:
    # ---------------- Get Finished Item ----------------
    finished_item = None
    finished_item_qty = 0

    for d in doc.items:
        if d.get("is_finished_item"):
            finished_item = d.item_code
            finished_item_qty = d.qty
            break

    if not finished_item:
        frappe.throw("No finished item found in Stock Entry.")

    # ---------------- Get Config ----------------
    qr_fg_doc = frappe.get_doc("QR Finished Goods")
    allowed_groups = {row.item_group for row in qr_fg_doc.finished_goods if row.item_group}
    packet_items = {row.item_code for row in qr_fg_doc.packet_items if row.item_code}

    finished_item_group = frappe.db.get_value("Item", finished_item, "item_group")
    has_packet_config = finished_item in packet_items

    if finished_item_group not in allowed_groups:
        frappe.log_error(
            "QR Batch Logic Skipped",
            f"Item group '{finished_item_group}' for item '{finished_item}' is not in QR Finished Goods config."
        )
    else:
        qr_codes = [row.qr_code for row in doc.table_cnlu if row.qr_code]

        # ---------------- Count Validation (Only if not a packet item) ----------------
        if not has_packet_config:
            if len(qr_codes) != finished_item_qty:
                frappe.throw(
                    f"Number of QR codes in 'qr code table' ({len(qr_codes)}) must match the quantity of finished items ({finished_item_qty})."
                )

        # ---------------- Duplicate Check ----------------
        if not doc.custom_batch_created:
            reused_codes = []
            for qr in qr_codes:
                if frappe.db.exists("Scan Log", {"qr_code": qr}):
                    reused_codes.append(qr)

            if reused_codes:
                msg = "The following QR codes have already been used and cannot be reused:<br>" + "<br>".join(reused_codes)
                frappe.throw(msg)

            # ---------------- Batch Creation ----------------
            timestamp = frappe.utils.now().replace(" ", "-").replace(":", "")
            batch_no = f"BATCH-{timestamp}"

            batch = frappe.get_doc({
                "doctype": "Batch",
                "batch_id": batch_no,
                "item": finished_item,
                "manufacturing_date": frappe.utils.nowdate()
            })
            batch.insert(ignore_permissions=True)

            for qr in qr_codes:
                batch.append("custom_batch_qr_code", {
                    "qr_code": qr,
                    "item": finished_item
                })
            batch.save(ignore_permissions=True)

            # ---------------- Link Batch to Stock Entry ----------------
            for d in doc.items:
                if d.get("is_finished_item"):
                    d.batch_no = batch_no

            doc.custom_batch_created = 1

            # ---------------- Update QR Logs ----------------
            for row in doc.table_cnlu:
                row.item_code = finished_item
                row.status = "Manufactured"
                row.manufacture_date = frappe.utils.nowdate()
                row.batch_no = batch_no

                frappe.get_doc({
                    "doctype": "Scan Log",
                    "qr_code": row.qr_code,
                    "item_code": finished_item,
                    "batch_no": batch_no,
                    "manufacture_date": frappe.utils.nowdate(),
                    "status": "Manufactured",
                    "stock_entry": doc.name,
                    "manufacture_reference": doc.name,
                    "date": frappe.utils.nowdate()
                }).insert(ignore_permissions=True)

            doc.save(ignore_permissions=True)

if doc.purpose != "Manufacture":
    frappe.msgprint("Not a manufacturing entry. Skipping validations and FG Store processing.")
else:
    finished_item = None
    finished_item_qty = 0

    # Identify the finished item
    for d in doc.items:
        if d.is_finished_item:
            finished_item = d.item_code
            finished_item_qty = d.qty
            break

    if not finished_item:
        frappe.throw("No finished item found in Stock Entry.")

    # Load QR Finished Goods config
    qr_finished_goods = frappe.get_doc("QR Finished Goods")

    # Check if finished item is a packet item
    is_packet_item = False
    packet_item_pieces = 0
    for packet_item in qr_finished_goods.packet_items:
        if packet_item.item_code == finished_item:
            is_packet_item = True
            packet_item_pieces = packet_item.no_of_pieces
            break

    if is_packet_item:
        frappe.msgprint(f"Finished item '{finished_item}' found in packet items with {packet_item_pieces} pieces. Skipping QR code quantity validations.")

        qr_codes_cnlu = [row.qr_code for row in doc.table_cnlu if row.qr_code]

        # Update CNLU table
        for row in doc.table_cnlu:
            row.item_code = finished_item
            row.status = "Manufactured"
            row.manufacture_date = frappe.utils.nowdate()

        # Mark CNLU QR codes as packets
        for qr_code in qr_codes_cnlu:
            frappe.db.set_value("Scan Log", {"qr_code": qr_code}, {
                "status": "FG Store",
                "date": frappe.utils.nowdate(),
                "is_packet": 1
            })

        # Attach packets to bags and update Scan Logs
        qr_codes_fg = [row.qr_code for row in doc.custom_fg_store_details if row.qr_code]
        doc.custom_fg_store_details = []

        packet_index = 0
        for bag_index, qr_code in enumerate(qr_codes_fg):
            attached_packets = []
            packets_to_attach = min(packet_item_pieces, len(qr_codes_cnlu) - packet_index)

            for i in range(packets_to_attach):
                if packet_index < len(qr_codes_cnlu):
                    packet_qr = qr_codes_cnlu[packet_index]
                    attached_packets.append(packet_qr)
                    frappe.db.set_value("Scan Log", {"qr_code": packet_qr}, "parent_qr_code", qr_code)
                    packet_index = packet_index + 1

            frappe.db.set_value("Scan Log", {"qr_code": qr_code}, {
                "status": "FG Store",
                "date": frappe.utils.nowdate(),
                "is_bag": 1,
                "attached_packets": ", ".join(attached_packets)
            })

            scan_log = frappe.get_doc("Scan Log", {"qr_code": qr_code})
            doc.append("custom_fg_store_details", {
                "qr_code": scan_log.qr_code,
                "item_code": scan_log.item_code,
                "status": scan_log.status,
                "manufacture_date": scan_log.manufacture_date,
                "batch_no": scan_log.batch_no
            })

    else:
        item_group = frappe.db.get_value("Item", finished_item, "item_group")
        allowed_item_groups = [row.item_group for row in qr_finished_goods.finished_goods]

        if item_group not in allowed_item_groups:
            frappe.msgprint(f"Item Group '{item_group}' of item '{finished_item}' is not listed in QR Finished Goods. Skipping QR validations.")
        else:
            # Validate QR code counts
            qr_codes_cnlu = [row.qr_code for row in doc.table_cnlu if row.qr_code]
            qr_codes_fg = [row.qr_code for row in doc.custom_fg_store_details if row.qr_code]
            set_cnlu = set(qr_codes_cnlu)
            set_fg = set(qr_codes_fg)

            if len(qr_codes_cnlu) != finished_item_qty:
                frappe.throw(f"'qr code table' QR code count ({len(qr_codes_cnlu)}) must match finished item qty ({finished_item_qty}).")
            if len(qr_codes_fg) != finished_item_qty:
                frappe.throw(f"'fg_store_codes' QR code count ({len(qr_codes_fg)}) must match finished item qty ({finished_item_qty}).")
            if set_cnlu != set_fg:
                parts = ["Mismatch between QR codes in 'qr code table' and 'fg_store_details'."]
                missing_in_fg = set_cnlu - set_fg
                missing_in_cnlu = set_fg - set_cnlu
                if missing_in_fg:
                    parts.append("Missing in 'fg_store_details': " + ", ".join(list(missing_in_fg)))
                if missing_in_cnlu:
                    parts.append("Missing in 'qr code table': " + ", ".join(list(missing_in_cnlu)))
                frappe.throw("<br>".join(parts))
            if sorted(qr_codes_cnlu) != sorted(qr_codes_fg):
                frappe.throw("Mismatch in QR code content. Ensure both tables contain identical, unduplicated QR codes.")

            # Update CNLU table
            for row in doc.table_cnlu:
                row.item_code = finished_item
                row.status = "Manufactured"
                row.manufacture_date = frappe.utils.nowdate()

            # Update Scan Logs and FG Store Table
            doc.custom_fg_store_details = []
            for qr_code in qr_codes_cnlu:
                frappe.db.set_value("Scan Log", {"qr_code": qr_code}, {
                    "status": "FG Store",
                    "date": frappe.utils.nowdate()
                })

                scan_log = frappe.get_doc("Scan Log", {"qr_code": qr_code})
                doc.append("custom_fg_store_details", {
                    "qr_code": scan_log.qr_code,
                    "item_code": scan_log.item_code,
                    "status": scan_log.status,
                    "manufacture_date": scan_log.manufacture_date,
                    "batch_no": scan_log.batch_no
                })

if doc.stock_entry_type == "Manufacture":
    qr_fg_doc = frappe.get_doc("QR Finished Goods")
    listed_groups = [row.item_group for row in qr_fg_doc.finished_goods]

    for item in doc.items:
        if item.is_finished_item:
            item_group = frappe.db.get_value("Item", item.item_code, "item_group")
            is_scannable = frappe.db.get_value("Item", item.item_code, "custom_is_scanned")

            if item_group in listed_groups and is_scannable:
                if not doc.custom_fg_store_details or len(doc.custom_fg_store_details) == 0:
                    frappe.throw("You must add at least one row in the Finished Goods Store Details before submitting.")
                break  # No need to check other items

# Only require sheets if this is NOT a return
if not doc.is_return:
    items_requiring_scanning = []

    # Check which items require scanning
    for item in doc.items:
        is_scanned = frappe.db.get_value("Item", item.item_code, "custom_is_scanned")
        if is_scanned:
            items_requiring_scanning.append(item.item_code)

    if items_requiring_scanning:
        # Require linked sheets
        if not doc.custom_loading_sheet:
            frappe.throw("Loading Sheet must be linked before submitting this Delivery Note (required for scanned items).")

        if not doc.custom_dispatch_sheet:
            frappe.throw("Dispatch Sheet must be linked before submitting this Delivery Note (required for scanned items).")

        # Validate that linked sheets are submitted
        ls_doc = frappe.get_doc("Loading Sheet", doc.custom_loading_sheet)
        if ls_doc.docstatus != 1:
            frappe.throw(f"Linked Loading Sheet {ls_doc.name} is not submitted.")

        ds_doc = frappe.get_doc("Dispatch Sheet", doc.custom_dispatch_sheet)
        if ds_doc.docstatus != 1:
            frappe.throw(f"Linked Dispatch Sheet {ds_doc.name} is not submitted.")

        frappe.msgprint("Scanned items in this Delivery Note: " + ", ".join(items_requiring_scanning))
    else:
        frappe.msgprint("No items in this Delivery Note require scanning. Skipping sheet validations.")

for ls_row in doc.loading_sheets:
    if ls_row.loading_sheet:
        loading_sheet = frappe.get_doc("Loading Sheet", ls_row.loading_sheet)
        for customer_row in loading_sheet.customer_details:
            if customer_row.delivery_notes:
                if frappe.db.exists("Delivery Note", customer_row.delivery_notes):
                    dn = frappe.get_doc("Delivery Note", customer_row.delivery_notes)
                    dn.custom_dispatch_sheet = doc.name
                    dn.save()

# Iterate through each row in the customer_details child table
for row in doc.customer_details:
    if row.delivery_notes:
        dn = frappe.get_doc("Delivery Note", row.delivery_notes)
        dn.custom_loading_sheet = doc.name
        dn.save()

# Block submission of Stock Entry of type "Manufacture" unless user has Stock Manager role
if doc.docstatus == 1 and doc.stock_entry_type == "Manufacture":
    if frappe.session.user != "Administrator":
        roles = [r.role for r in frappe.get_all("Has Role", filters={"parent": frappe.session.user}, fields=["role"])]
        if "Stock Manager" not in roles:
            frappe.throw("Only users with the Stock Manager role can submit Stock Entries of type 'Manufacture'.")
